   327→struct JoinGroupSheet: View {
   328→    @Environment(\.dismiss) private var dismiss
   329→    let resolver: Resolver
   330→    let onJoined: () -> Void
   331→
   332→    @State private var inviteCode = ""
   333→    @State private var isLoading = false
   334→    @State private var errorMessage: String?
   335→
   336→    var body: some View {
   337→        NavigationStack {
   338→            Form {
   339→                Section {
   340→                    TextField("Código de convite", text: $inviteCode)
   341→                        .autocorrectionDisabled()
   342→                        .textInputAutocapitalization(.characters)
   343→                } header: {
   344→                    Text("Código de Convite")
   345→                } footer: {
   346→                    Text("Peça o código de convite para o administrador do grupo")
   347→                }
   348→
   349→                if let error = errorMessage {
   350→                    Section {
   351→                        Text(error)
   352→                            .foregroundStyle(FitTodayColor.error)
   353→                            .font(FitTodayFont.ui(size: 14, weight: .medium))
   354→                    }
   355→                }
   356→            }
   357→            .navigationTitle("Entrar em Grupo")
   358→            .navigationBarTitleDisplayMode(.inline)
   359→            .toolbar {
   360→                ToolbarItem(placement: .cancellationAction) {
   361→                    Button("Cancelar") {
   362→                        dismiss()
   363→                    }
   364→                }
   365→
   366→                ToolbarItem(placement: .confirmationAction) {
   367→                    Button("Entrar") {
   368→                        Task {
   369→                            await joinGroup()
   370→                        }
   371→                    }
   372→                    .disabled(inviteCode.isEmpty || isLoading)
   373→                }
   374→            }
   375→            .disabled(isLoading)
   376→        }
   377→    }
   378→
   379→    private func joinGroup() async {
   380→        guard !inviteCode.isEmpty else { return }
   381→
   382→        isLoading = true
   383→        errorMessage = nil
   384→
   385→        defer { isLoading = false }
   386→
   387→        guard let joinUseCase = resolver.resolve(JoinGroupUseCase.self) else {
   388→            errorMessage = "Serviço não disponível"
   389→            return
   390→        }
   391→
   392→        do {
   393→            try await joinUseCase.execute(groupId: inviteCode)
   394→            dismiss()
   395→            onJoined()
   396→        } catch {
   397→            errorMessage = "Não foi possível entrar no grupo: \(error.localizedDescription)"
   398→        }
   399→    }
   400→}
