   420→                            .foregroundStyle(FitTodayColor.textPrimary)
   421→
   422→                        HStack(spacing: FitTodaySpacing.xs) {
   423→                            Image(systemName: "person.2.fill")
   424→                                .font(.system(size: 10))
   425→                            Text("\(challenge.participants) participantes")
   426→                                .font(FitTodayFont.ui(size: 11, weight: .medium))
   427→                        }
   428→                        .foregroundStyle(FitTodayColor.textTertiary)
   429→                    }
   430→
   431→                    Spacer()
   432→
   433→                    if challenge.progress >= 1.0 {
   434→                        Image(systemName: "checkmark.seal.fill")
