   445→                                    .font(FitTodayFont.ui(size: 11, weight: .medium))
   446→                                    .foregroundStyle(FitTodayColor.textTertiary)
   447→                            }
   448→                        }
   449→                    }
   450→                }
   451→
   452→                // Progress Bar
   453→                GeometryReader { geometry in
   454→                    ZStack(alignment: .leading) {
