   277→    private func loadCustomization() async {
   278→        guard let repository = resolver.resolve(ProgramWorkoutCustomizationRepositoryProtocol.self) else {
   279→            isLoadingCustomization = false
   280→            return
   281→        }
   282→
   283→        if let customization = await repository.getCustomization(for: workout.id) {
   284→            deletedExerciseIds = customization.deletedExerciseIds
   285→            var filteredExercises = workout.exercises.filter { !customization.deletedExerciseIds.contains($0.id) }
   286→
   287→            if !customization.exerciseOrder.isEmpty {
   288→                let orderMap = Dictionary(uniqueKeysWithValues: customization.exerciseOrder.enumerated().map { ($1, $0) })
   289→                filteredExercises.sort { ex1, ex2 in
   290→                    let order1 = orderMap[ex1.id] ?? Int.max
   291→                    let order2 = orderMap[ex2.id] ?? Int.max
   292→                    return order1 < order2
   293→                }
   294→            }
   295→
   296→            exercises = filteredExercises
   297→        }
   298→
   299→        isLoadingCustomization = false
   300→    }
