   347→    private func createWorkoutExercise(from programExercise: ProgramExercise) -> WorkoutExercise {
   348→        let catalog = programExercise.catalogExercise
   349→        let muscleGroup = MuscleGroup(rawValue: catalog.category ?? "") ?? .fullBody
   350→
   351→        let instructions: [String] = {
   352→            guard let desc = catalog.description, !desc.isEmpty else {
   353→                return ["Realize o exercicio com boa tecnica."]
   354→            }
   355→            let lines = desc
   356→                .components(separatedBy: CharacterSet.newlines)
   357→                .map { $0.trimmingCharacters(in: .whitespaces) }
   358→                .filter { !$0.isEmpty }
   359→            return lines.isEmpty ? ["Realize o exercicio com boa tecnica."] : lines
   360→        }()
   361→
   362→        return WorkoutExercise(
   363→            id: catalog.id,
   364→            name: catalog.name,
   365→            mainMuscle: muscleGroup,
   366→            equipment: mapEquipment(catalog.equipment),
   367→            instructions: instructions,
   368→            media: nil
   369→        )
   370→    }
   371→
   372→    private func mapEquipment(_ equipmentIds: [Int]) -> EquipmentType {
   373→        guard let first = equipmentIds.first else { return .bodyweight }
   374→        switch first {
   375→        case 1: return .barbell
   376→        case 3: return .dumbbell
   377→        case 8: return .machine
   378→        case 10: return .kettlebell
   379→        case 7: return .bodyweight
   380→        case 9: return .resistanceBand
   381→        case 6: return .pullupBar
   382→        default: return .bodyweight
   383→        }
   384→    }
   385→}
